 bisection #include <iostream>
#include <cmath>
#include <iomanip>
using namespace std;

#define EP 0.01

double solution(double x) {
    return x*x*x - 4*x - 9;
}

void bisection(double a, double b) {
    if (solution(a) * solution(b) >= 0) {
        cout << "Invalid interval. Try again.\n";
        return;
    }

    double c;
    int count = 0;

    cout << fixed << setprecision(4);
    cout << "\nIter\t a\t\t b\t\t c\t\t f(c)\n";
    cout << "------------------------------------------------------------\n";

    while (fabs(b - a) >= EP) {
        c = (a + b) / 2;

        cout << count << "\t " << a << "\t " << b << "\t " 
             << c << "\t " << solution(c) << endl;

        if (fabs(solution(c)) < EP) {
            break;
        }
        else if (solution(a) * solution(c) < 0) {
            b = c;
        }
        else {
            a = c;
        }

        count++;
    }

    cout << "\nRoot = " << c << endl;
    cout << "Total iterations = " << count << endl;
}

int main() {
    double a = 2, b = 3;
    bisection(a, b);
    return 0;
}
